import{_ as s,o as a,c as t,e as p}from"./app-cb4a12e2.js";const e={};function o(c,n){return a(),t("div",null,[...n[0]||(n[0]=[p(`<h1 id="别再乱装库了-这-10-个浏览器原生-api-早就解决了你的问题" tabindex="-1"><a class="header-anchor" href="#别再乱装库了-这-10-个浏览器原生-api-早就解决了你的问题" aria-hidden="true">#</a> 别再乱装库了：这 10 个浏览器原生 API 早就解决了你的问题</h1><p>Web 平台的能力远比大多数开发者想象的要强大——而且每年都在悄悄地增加新的“超能力”。</p><p>有时候，想选题比写文章本身还难。</p><p>当我在想这周写点什么的时候，脑子里只有两种想法：要么是那种“爆炸性”的大新闻，要么是深度的技术硬核文。😅 但我想要点更轻松的。既要有技术含量，又要实用，但别让人掉进三天爬不出来的研究兔子洞里。</p><p>既然我真心喜欢探索浏览器的极限（以及我们能把它推到多远），我决定聊个“狡猾”的话题：<strong>那些被低估的 Web API</strong>。</p><p>其中一些可能是你的家常便饭。 但我敢打赌，至少有几个会让某些人惊呼：“等一下，还有这玩意儿？！” 😉</p><p>好了，废话不多说。让我们开始吧。</p><p>这里有 10 个值得更多关爱的浏览器原生 API。</p><hr><h2 id="_1-structured-clone-api-结构化克隆" tabindex="-1"><a class="header-anchor" href="#_1-structured-clone-api-结构化克隆" aria-hidden="true">#</a> 1) Structured Clone API (结构化克隆)</h2><p>我对这个 API 真是爱恨交加。</p><p>多年来，我最喜欢的面试题之一就是：<strong>“你如何深拷贝一个对象？”</strong></p><p>你可以从答案中学到很多东西：他们懂引用吗？懂 <code>Object.assign</code> 和 <code>JSON</code> 黑魔法吗？会提到第三方库（如 Lodash）吗？还是直接慌了？ 😄</p><p>现在呢？</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> calendarEvent <span class="token operator">=</span> <span class="token punctuation">{</span>
  <span class="token literal-property property">title</span><span class="token operator">:</span> <span class="token string">&quot;Meeting&quot;</span><span class="token punctuation">,</span>
  <span class="token literal-property property">date</span><span class="token operator">:</span> <span class="token keyword">new</span> <span class="token class-name">Date</span><span class="token punctuation">(</span><span class="token number">123</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
  <span class="token literal-property property">attendees</span><span class="token operator">:</span> <span class="token keyword">new</span> <span class="token class-name">Set</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token string">&quot;Alice&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;Bob&quot;</span><span class="token punctuation">]</span><span class="token punctuation">)</span>
<span class="token punctuation">}</span><span class="token punctuation">;</span>

<span class="token comment">// ❌ JSON 大法：Date 变字符串，Set 变空对象 {}</span>
<span class="token keyword">const</span> jsonCopy <span class="token operator">=</span> <span class="token constant">JSON</span><span class="token punctuation">.</span><span class="token function">parse</span><span class="token punctuation">(</span><span class="token constant">JSON</span><span class="token punctuation">.</span><span class="token function">stringify</span><span class="token punctuation">(</span>calendarEvent<span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// ✅ Structured Clone：完美还原 Date 和 Set</span>
<span class="token keyword">const</span> realCopy <span class="token operator">=</span> <span class="token function">structuredClone</span><span class="token punctuation">(</span>calendarEvent<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Boom。完美的深拷贝。</p><p><strong>为什么它比 JSON 大法好？</strong></p><ul><li>✅ <strong>支持更多类型</strong>：<code>JSON</code> 方法会把 <code>Date</code> 变成字符串，把 <code>Map</code> 和 <code>Set</code> 弄丢，甚至忽略 <code>undefined</code>。而 <code>structuredClone</code> 能完美还原它们，还支持 <code>Blob</code>, <code>File</code>, <code>ArrayBuffer</code> 等二进制类型。</li><li>✅ <strong>不怕循环引用</strong>：如果对象 A 引用了 B，B 又引用了 A，用 JSON 方法会直接报错（栈溢出爆炸 💥）。<code>structuredClone</code> 则能轻松搞定。</li><li>❌ <strong>注意</strong>：它<strong>不能</strong>克隆函数（会抛错），不过在处理纯数据时这通常不是问题。</li></ul><p><strong>支持情况</strong>：现代浏览器 (Chrome, Firefox, Safari, Edge)。生产环境安全。</p><hr><h2 id="_2-performance-api" tabindex="-1"><a class="header-anchor" href="#_2-performance-api" aria-hidden="true">#</a> 2) Performance API</h2><p>严重被低估。我们经常谈论性能，安装各种工具，跑 Lighthouse，但有时候你只是想确认一下：<strong>“A 真的比 B 快吗，还是我在过度设计？”</strong></p><p>你可能会想用 <code>Date.now()</code>，但它精度不够，且受系统时间修改影响。<code>performance.now()</code> 才是正解。</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>performance<span class="token punctuation">.</span><span class="token function">mark</span><span class="token punctuation">(</span><span class="token string">&quot;start&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// 这里放你要测量的代码（比如一个复杂的循环）</span>
<span class="token function">doHeavyWork</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

performance<span class="token punctuation">.</span><span class="token function">mark</span><span class="token punctuation">(</span><span class="token string">&quot;end&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
performance<span class="token punctuation">.</span><span class="token function">measure</span><span class="token punctuation">(</span><span class="token string">&quot;my-benchmark&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;start&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;end&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// 获取高精度测量结果</span>
<span class="token keyword">const</span> entries <span class="token operator">=</span> performance<span class="token punctuation">.</span><span class="token function">getEntriesByName</span><span class="token punctuation">(</span><span class="token string">&quot;my-benchmark&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span>entries<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token punctuation">.</span>duration <span class="token operator">+</span> <span class="token string">&quot;ms&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>非常适合：</strong></p><ul><li>微基准测试 (Micro-benchmarks)</li><li>检查 Web Worker 或 WASM 是否真的带来了性能提升（加上通信成本后）</li><li>对你的假设进行“现实核查”，因为有时候，“优化后”的版本反而更慢 😅</li></ul><p><strong>支持情况</strong>：所有现代浏览器完美支持。</p><hr><h2 id="_3-page-visibility-api-页面可见性" tabindex="-1"><a class="header-anchor" href="#_3-page-visibility-api-页面可见性" aria-hidden="true">#</a> 3) Page Visibility API (页面可见性)</h2><p>检测标签页是否处于激活状态。</p><p>不要再用 <code>window.onblur</code> 或 <code>window.onfocus</code> 了，它们在用户只是点击了另一个窗口（但你的页面还在屏幕上可见）时也会触发。</p><p><code>visibilitychange</code> 才是检测“用户是否真的在看页面”的正确方式。</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code>document<span class="token punctuation">.</span><span class="token function">addEventListener</span><span class="token punctuation">(</span><span class="token string">&quot;visibilitychange&quot;</span><span class="token punctuation">,</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
  <span class="token comment">// document.visibilityState 可以是 &#39;visible&#39;, &#39;hidden&#39;, &#39;prerender&#39;</span>
  <span class="token keyword">if</span> <span class="token punctuation">(</span>document<span class="token punctuation">.</span>visibilityState <span class="token operator">===</span> <span class="token string">&#39;hidden&#39;</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment">// 用户切走了：暂停视频、停止轮询、停止复杂的 Canvas 动画</span>
    video<span class="token punctuation">.</span><span class="token function">pause</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token function">stopPolling</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>
    <span class="token comment">// 用户回来了：恢复一切</span>
    video<span class="token punctuation">.</span><span class="token function">play</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token function">startPolling</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>使用场景：</strong></p><ul><li>节省带宽：用户不看时，别再每秒请求一次接口了。</li><li>节省电量：暂停高能耗的动画。</li><li>更精准的数据分析：计算用户的<strong>真实阅读时长</strong>。</li></ul><p><strong>支持情况</strong>：所有现代浏览器。</p><hr><h2 id="_4-resizeobserver" tabindex="-1"><a class="header-anchor" href="#_4-resizeobserver" aria-hidden="true">#</a> 4) ResizeObserver</h2><p>终于来了——监听<strong>元素</strong>的大小，而不仅仅是窗口大小 (<code>window.resize</code>)。</p><p>以前，如果一个侧边栏折叠导致主内容区变宽，或者一个文本框被用户拖大，<code>window.resize</code> 根本不会触发。你只能写一堆烂代码去轮询或者 hack。</p><p>现在：</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> ro <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">ResizeObserver</span><span class="token punctuation">(</span><span class="token parameter">entries</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
  <span class="token keyword">for</span> <span class="token punctuation">(</span><span class="token keyword">const</span> entry <span class="token keyword">of</span> entries<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment">// 获取元素的精确尺寸信息</span>
    <span class="token keyword">const</span> <span class="token punctuation">{</span> width<span class="token punctuation">,</span> height <span class="token punctuation">}</span> <span class="token operator">=</span> entry<span class="token punctuation">.</span>contentRect<span class="token punctuation">;</span>
    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token template-string"><span class="token template-punctuation string">\`</span><span class="token string">Element size: </span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span>width<span class="token interpolation-punctuation punctuation">}</span></span><span class="token string">x</span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span>height<span class="token interpolation-punctuation punctuation">}</span></span><span class="token template-punctuation string">\`</span></span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    
    <span class="token comment">// 比如：如果宽度小于 500px，就切换到“紧凑模式”</span>
    <span class="token keyword">if</span> <span class="token punctuation">(</span>width <span class="token operator">&lt;</span> <span class="token number">500</span><span class="token punctuation">)</span> element<span class="token punctuation">.</span>classList<span class="token punctuation">.</span><span class="token function">add</span><span class="token punctuation">(</span><span class="token string">&#39;compact&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// 监听任何 DOM 元素</span>
ro<span class="token punctuation">.</span><span class="token function">observe</span><span class="token punctuation">(</span>document<span class="token punctuation">.</span><span class="token function">querySelector</span><span class="token punctuation">(</span><span class="token string">&#39;.sidebar&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
ro<span class="token punctuation">.</span><span class="token function">observe</span><span class="token punctuation">(</span>document<span class="token punctuation">.</span><span class="token function">querySelector</span><span class="token punctuation">(</span><span class="token string">&#39;.main-content&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这个 API 就像浏览器在对你说：“放轻松，布局变化交给我。”</p><p><strong>支持情况</strong>：现代浏览器广泛支持。</p><hr><h2 id="_5-intersectionobserver" tabindex="-1"><a class="header-anchor" href="#_5-intersectionobserver" aria-hidden="true">#</a> 5) IntersectionObserver</h2><p>ResizeObserver 的兄弟。它检查<strong>元素是否进入了视口（Viewport）</strong>。</p><p>以前我们怎么做无限滚动？监听 <code>scroll</code> 事件，疯狂计算 <code>getBoundingClientRect()</code>，这会让主线程卡顿，导致页面滚动不流畅。</p><p>IntersectionObserver 是异步的，高性能的。</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> observer <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">IntersectionObserver</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token parameter">entries</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
  entries<span class="token punctuation">.</span><span class="token function">forEach</span><span class="token punctuation">(</span><span class="token parameter">entry</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
    <span class="token keyword">if</span> <span class="token punctuation">(</span>entry<span class="token punctuation">.</span>isIntersecting<span class="token punctuation">)</span> <span class="token punctuation">{</span>
      <span class="token comment">// 元素进入视口了！</span>
      console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&quot;加载更多数据...&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
      <span class="token function">loadMoreItems</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
      
      <span class="token comment">// 如果只需要触发一次（比如懒加载图片），用完记得取消监听</span>
      observer<span class="token punctuation">.</span><span class="token function">unobserve</span><span class="token punctuation">(</span>entry<span class="token punctuation">.</span>target<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
  <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token punctuation">{</span>
  <span class="token literal-property property">rootMargin</span><span class="token operator">:</span> <span class="token string">&#39;100px&#39;</span> <span class="token comment">// 提前 100px 触发，让用户感觉不到加载过程</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// 监听列表底部的那个“加载中”转圈圈元素</span>
observer<span class="token punctuation">.</span><span class="token function">observe</span><span class="token punctuation">(</span>document<span class="token punctuation">.</span><span class="token function">querySelector</span><span class="token punctuation">(</span><span class="token string">&#39;#loading-spinner&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>神器用于：</strong></p><ul><li>无限滚动 (Infinite scroll)</li><li>图片懒加载 (Lazy loading)</li><li>埋点曝光（只有用户真的滑到了广告，才算一次展示）</li></ul><p><strong>支持情况</strong>：所有现代浏览器。</p><hr><h2 id="_6-abortcontroller" tabindex="-1"><a class="header-anchor" href="#_6-abortcontroller" aria-hidden="true">#</a> 6) AbortController</h2><p>很多开发者知道它是配合 <code>fetch</code> 用来取消请求的，但它的能力远不止于此。</p><p>它是一个通用的“取消信号”机制。</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token keyword">const</span> controller <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">AbortController</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token keyword">const</span> <span class="token punctuation">{</span> signal <span class="token punctuation">}</span> <span class="token operator">=</span> controller<span class="token punctuation">;</span>

<span class="token comment">// 1. 取消 Fetch 请求</span>
<span class="token function">fetch</span><span class="token punctuation">(</span>url<span class="token punctuation">,</span> <span class="token punctuation">{</span> signal <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">catch</span><span class="token punctuation">(</span><span class="token parameter">err</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
  <span class="token keyword">if</span> <span class="token punctuation">(</span>err<span class="token punctuation">.</span>name <span class="token operator">===</span> <span class="token string">&#39;AbortError&#39;</span><span class="token punctuation">)</span> console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;请求被取消&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// 2. 一键移除事件监听器（不用再保存函数引用了！）</span>
window<span class="token punctuation">.</span><span class="token function">addEventListener</span><span class="token punctuation">(</span><span class="token string">&#39;resize&#39;</span><span class="token punctuation">,</span> handleResize<span class="token punctuation">,</span> <span class="token punctuation">{</span> signal <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// 3. 取消任何支持 signal 的异步操作</span>
<span class="token function">doSomethingAsync</span><span class="token punctuation">(</span><span class="token punctuation">{</span> signal <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// 💥 一声令下，全部取消</span>
controller<span class="token punctuation">.</span><span class="token function">abort</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>更棒的是：</strong> 👉 一个信号可以同时传递给多个操作。比如用户点击“取消”按钮时，同时取消 3 个 API 请求和 2 个事件监听器。</p><p><strong>支持情况</strong>：所有现代浏览器。</p><hr><h2 id="_7-idle-detection-api-空闲检测" tabindex="-1"><a class="header-anchor" href="#_7-idle-detection-api-空闲检测" aria-hidden="true">#</a> 7) Idle Detection API (空闲检测)</h2><p>Page Visibility 告诉你标签页是否激活。 Idle Detection 告诉你<strong>人</strong>是否激活。</p><p>这有什么区别？ 用户可能把你的即时通讯软件挂在第二个屏幕上（页面可见），但他本人其实去开会了（系统空闲）。</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 需要用户授权权限</span>
<span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token keyword">await</span> IdleDetector<span class="token punctuation">.</span><span class="token function">requestPermission</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">===</span> <span class="token string">&#39;granted&#39;</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token keyword">const</span> detector <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">IdleDetector</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  
  detector<span class="token punctuation">.</span><span class="token function">addEventListener</span><span class="token punctuation">(</span><span class="token string">&quot;change&quot;</span><span class="token punctuation">,</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
    <span class="token keyword">const</span> <span class="token punctuation">{</span> userState<span class="token punctuation">,</span> screenState <span class="token punctuation">}</span> <span class="token operator">=</span> detector<span class="token punctuation">;</span>
    console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token template-string"><span class="token template-punctuation string">\`</span><span class="token string">用户状态: </span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span>userState<span class="token interpolation-punctuation punctuation">}</span></span><span class="token string">, 屏幕状态: </span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span>screenState<span class="token interpolation-punctuation punctuation">}</span></span><span class="token template-punctuation string">\`</span></span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    
    <span class="token keyword">if</span> <span class="token punctuation">(</span>userState <span class="token operator">===</span> <span class="token string">&#39;idle&#39;</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
      <span class="token function">updateStatusToAway</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 自动把状态改成“离开”</span>
    <span class="token punctuation">}</span>
  <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

  <span class="token keyword">await</span> detector<span class="token punctuation">.</span><span class="token function">start</span><span class="token punctuation">(</span><span class="token punctuation">{</span> <span class="token literal-property property">threshold</span><span class="token operator">:</span> <span class="token number">60000</span> <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 1分钟无操作算空闲</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>使用场景：</strong></p><ul><li>聊天软件自动切换“忙碌/离开”状态</li><li>银行应用自动登出</li><li>停止高消耗的后台计算以省电</li></ul><p><strong>注意</strong>：这有点涉及隐私，所以必须经过用户明确许可。</p><p><strong>支持情况</strong>：主要是 Chromium 内核浏览器。</p><hr><h2 id="_8-broadcastchannel-api" tabindex="-1"><a class="header-anchor" href="#_8-broadcastchannel-api" aria-hidden="true">#</a> 8) BroadcastChannel API</h2><p>简单的多标签页通信。</p><p>以前我们要在两个 Tab 之间同步数据，得用 <code>localStorage</code> 监听 <code>storage</code> 事件，或者搞个 SharedWorker，都很麻烦。</p><p><code>BroadcastChannel</code> 就像一个对讲机，只要频道名称一样，大家都能听到。</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 在 Tab A 中</span>
<span class="token keyword">const</span> channel <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">BroadcastChannel</span><span class="token punctuation">(</span><span class="token string">&quot;my-app-channel&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
channel<span class="token punctuation">.</span><span class="token function">postMessage</span><span class="token punctuation">(</span><span class="token punctuation">{</span> <span class="token literal-property property">type</span><span class="token operator">:</span> <span class="token string">&#39;LOGOUT&#39;</span><span class="token punctuation">,</span> <span class="token literal-property property">user</span><span class="token operator">:</span> <span class="token string">&#39;rain9&#39;</span> <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// 在 Tab B 中 (无需引用 Tab A)</span>
<span class="token keyword">const</span> channel <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">BroadcastChannel</span><span class="token punctuation">(</span><span class="token string">&quot;my-app-channel&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
channel<span class="token punctuation">.</span><span class="token function-variable function">onmessage</span> <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token parameter">event</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
  <span class="token keyword">if</span> <span class="token punctuation">(</span>event<span class="token punctuation">.</span>data<span class="token punctuation">.</span>type <span class="token operator">===</span> <span class="token string">&#39;LOGOUT&#39;</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token function">alert</span><span class="token punctuation">(</span><span class="token string">&quot;您已在其他页面登出&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    window<span class="token punctuation">.</span>location<span class="token punctuation">.</span><span class="token function">reload</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>非常适合：</strong></p><ul><li>用户在一个标签页登出，所有标签页自动跳转登录页</li><li>主题切换同步（这边切黑夜模式，那边也跟着黑）</li><li>数据变更通知</li></ul><p><strong>支持情况</strong>：现代浏览器。Safari 后来也跟进支持了。</p><hr><h2 id="_9-web-locks-api" tabindex="-1"><a class="header-anchor" href="#_9-web-locks-api" aria-hidden="true">#</a> 9) Web Locks API</h2><p>BroadcastChannel 的表亲。防止跨标签页的<strong>竞态条件 (Race Conditions)</strong>。</p><p>想象一下：用户打开了 5 个标签页，你的应用启动时会去同步大量数据。你不想让 5 个标签页同时去轰炸后端 API，对吧？</p><p>Web Locks 让你能“加锁”。</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 请求一个叫 &#39;my-sync-lock&#39; 的锁</span>
navigator<span class="token punctuation">.</span>locks<span class="token punctuation">.</span><span class="token function">request</span><span class="token punctuation">(</span><span class="token string">&quot;my-sync-lock&quot;</span><span class="token punctuation">,</span> <span class="token keyword">async</span> <span class="token punctuation">(</span><span class="token parameter">lock</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
  <span class="token comment">// 只有获得锁的那个标签页才会执行这里的代码</span>
  <span class="token comment">// 其他标签页会排队等待，或者直接被告知“锁被占用了”</span>
  
  <span class="token keyword">await</span> <span class="token function">syncDataFromBackend</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  console<span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&quot;同步完成&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>使用场景：</strong></p><ul><li>主从模式 (Leader Election)：选一个 Tab 当“主 Tab”负责处理 WebSocket 或定时任务。</li><li>防止多个 Tab 同时写入 IndexedDB 导致冲突。</li></ul><p>感觉非常有“分布式系统遇上前端”的味道。</p><p><strong>支持情况</strong>：主要是 Chromium。并非全平台通用，但 Polyfill 很容易写。</p><hr><h2 id="_10-file-system-access-api" tabindex="-1"><a class="header-anchor" href="#_10-file-system-access-api" aria-hidden="true">#</a> 10) File System Access API</h2><p>是的——浏览器里的<strong>真实</strong>文件系统访问权限。</p><p>不再是简单的 <code>&lt;input type=&quot;file&quot;&gt;</code> 上传了。你可以<strong>打开</strong>一个文件，修改它，然后<strong>直接保存回原文件</strong>。就像 VS Code 网页版那样。</p><div class="language-javascript line-numbers-mode" data-ext="js"><pre class="language-javascript"><code><span class="token comment">// 1. 让用户选择一个文件</span>
<span class="token keyword">const</span> <span class="token punctuation">[</span>fileHandle<span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token keyword">await</span> window<span class="token punctuation">.</span><span class="token function">showOpenFilePicker</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// 2. 读取内容</span>
<span class="token keyword">const</span> file <span class="token operator">=</span> <span class="token keyword">await</span> fileHandle<span class="token punctuation">.</span><span class="token function">getFile</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token keyword">const</span> text <span class="token operator">=</span> <span class="token keyword">await</span> file<span class="token punctuation">.</span><span class="token function">text</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">// 3. 修改后写回（需要再次请求写入权限）</span>
<span class="token keyword">const</span> writable <span class="token operator">=</span> <span class="token keyword">await</span> fileHandle<span class="token punctuation">.</span><span class="token function">createWritable</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token keyword">await</span> writable<span class="token punctuation">.</span><span class="token function">write</span><span class="token punctuation">(</span><span class="token string">&quot;这是新追加的内容！&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token keyword">await</span> writable<span class="token punctuation">.</span><span class="token function">close</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>非常适合：</strong></p><ul><li>Web 版代码编辑器 / Markdown 编辑器</li><li>图片处理工具（直接覆盖原图）</li><li>本地配置文件的导入导出</li></ul><p>第一次使用时，感觉有点违规。就像“我们真的被允许在 Web 上做这个吗？” 😄 当然，浏览器会弹出非常显眼的权限提示框。</p><p><strong>支持情况</strong>：Chromium 为主。其他浏览器限制较多。</p><hr><h2 id="现实核查-reality-check-🧠" tabindex="-1"><a class="header-anchor" href="#现实核查-reality-check-🧠" aria-hidden="true">#</a> 现实核查 (Reality Check) 🧠</h2><p>这些 API 中的大多数在现代浏览器中都有很好的支持。但有些（Idle Detection, File System Access, Web Locks）仍然是以 Chromium 为中心的。</p><p>所以在全力投入之前，一定要检查兼容性。</p><p>但仅仅知道它们的存在？这已经给了你优势。</p><p>Web 平台发展迅速。有时候，“新技术”不是某个框架——而是那个一直静静待在那里的原生浏览器特性。</p>`,103)])])}const l=s(e,[["render",o],["__file","Browser.html.vue"]]);export{l as default};
